class Solution(object):
    def isWinner(self, player1, player2):
        def score(pins):
            total = 0
            for i, p in enumerate(pins):
                if (i >= 1 and pins[i - 1] == 10) or (i >= 2 and pins[i - 2] == 10):
                    total += p * 2
                else:
                    total += p
            return total
        s1, s2 = score(player1), score(player2)
        if s1 > s2:
            return 1
        if s2 > s1:
            return 2
        return 0
